<?php
namespace App\Modules\Hr\Performance\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Performance\Enums\PerformanceEvaluationStatus; use App\Modules\Hr\Performance\Enums\ReviewerType; use App\Modules\Hr\Performance\Models\HrPerformanceCycle; use App\Modules\Hr\Performance\Models\HrPerformanceEvaluation; use App\Modules\Hr\Performance\Models\HrPerformanceTemplate; use App\Modules\Hr\Personnel\Models\HrEmployee;
class CreateEvaluationAssignmentAction { public function __construct(private HrAuditService $audit){} public function execute(HrPerformanceCycle $cycle,HrPerformanceTemplate $template,HrEmployee $employee,HrEmployee $reviewer,ReviewerType $type):HrPerformanceEvaluation{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.performance.manage_templates'),403);abort_unless($cycle->legal_entity_id===$tenant&&$template->legal_entity_id===$tenant&&$employee->legal_entity_id===$tenant&&$reviewer->legal_entity_id===$tenant,404);abort_if($type===ReviewerType::Self&&$reviewer->id!==$employee->id,422,'Öz değerlendirme çalışan tarafından yapılmalıdır.');$evaluation=HrPerformanceEvaluation::firstOrCreate(['cycle_id'=>$cycle->id,'employee_id'=>$employee->id,'reviewer_employee_id'=>$reviewer->id,'reviewer_type'=>$type->value],['legal_entity_id'=>$tenant,'template_id'=>$template->id,'status'=>PerformanceEvaluationStatus::Draft]);$this->audit->log('performance_evaluation_assigned',$evaluation,null,['reviewer_type'=>$type->value]);return $evaluation;} }
